import React, { useState, useEffect } from 'react';
import {
  LayoutDashboard,
  Users,
  Phone,
  Headphones,
  FileText,
  BarChart3,
  Settings,
  Menu,
  X,
  Activity,
  PhoneCall,
  UserPlus,
  Plus,
  Edit,
  Trash2,
  Play,
  Pause,
  Download,
  RefreshCw,
  Power,
  Clock,
  TrendingUp,
  PhoneMissed,
  Search,
  Filter,
  Calendar,
  Volume2,
  Database,
  Wifi,
  Zap,
  TrendingDown,
  Eye,
  WifiOff,
} from 'lucide-react';
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  PieChart,
  Pie,
  Cell,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || 'http://localhost:3000';

// Utility function for API calls
const apiCall = async (endpoint, method = 'GET', body = null) => {
  try {
    const options = {
      method,
      headers: { 'Content-Type': 'application/json' },
    };
    if (body) options.body = JSON.stringify(body);

    const response = await fetch(`${API_BASE_URL}${endpoint}`, options);

    // Handle 204 No Content (for DELETE operations)
    if (response.status === 204) {
      return { success: true, data: null };
    }

    const data = await response.json();

    // Support both old (data.error) and new (data.message) error formats
    if (!response.ok)
      throw new Error(data.error || data.message || 'Erreur API');
    return data;
  } catch (error) {
    console.error('API Error:', error);
    throw error;
  }
};

// Stat Card Component with gradient and animation
const StatCard = ({ title, value, icon, color, trend }) => {
  const colors = {
    blue: 'from-blue-500 to-blue-600',
    green: 'from-green-500 to-green-600',
    yellow: 'from-yellow-500 to-orange-500',
    purple: 'from-purple-500 to-purple-600',
    red: 'from-red-500 to-red-600',
    orange: 'from-orange-500 to-orange-600',
  };

  return (
    <div className="relative overflow-hidden bg-white rounded-2xl shadow-xl hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1">
      <div
        className={`absolute inset-0 bg-gradient-to-br ${colors[color]} opacity-5`}
      ></div>
      <div className="relative p-6">
        <div className="flex items-center justify-between mb-4">
          <div
            className={`p-3 rounded-xl bg-gradient-to-br ${colors[color]} shadow-lg`}
          >
            <div className="text-white">{icon}</div>
          </div>
          {trend && (
            <div
              className={`flex items-center gap-1 text-sm font-semibold ${
                trend > 0 ? 'text-green-600' : 'text-red-600'
              }`}
            >
              {trend > 0 ? (
                <TrendingUp className="w-4 h-4" />
              ) : (
                <TrendingDown className="w-4 h-4" />
              )}
              {Math.abs(trend)}%
            </div>
          )}
        </div>
        <div>
          <p className="text-sm text-gray-500 font-medium mb-1">{title}</p>
          <p className="text-3xl font-bold text-gray-900 tracking-tight">
            {value}
          </p>
        </div>
      </div>
    </div>
  );
};

// Modal Component with enhanced design
const Modal = ({ children, onClose, title }) => {
  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-fadeIn">
      <div className="bg-white rounded-3xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto transform animate-slideUp">
        <div className="sticky top-0 bg-gradient-to-r from-blue-600 to-purple-600 text-white p-6 rounded-t-3xl">
          <div className="flex justify-between items-center">
            <h2 className="text-2xl font-bold">{title}</h2>
            <button
              onClick={onClose}
              className="p-2 hover:bg-white hover:bg-opacity-20 rounded-xl transition-all"
            >
              <X className="w-6 h-6" />
            </button>
          </div>
        </div>
        <div className="p-6">{children}</div>
      </div>
    </div>
  );
};

// Login Component
const LoginPage = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = e => {
    e.preventDefault();
    if (username === 'kamgoko' && password === 'fIxSRtVP9q0ajtkc') {
      localStorage.setItem('isAuthenticated', 'true');
      onLogin();
    } else {
      setError('Identifiants incorrects');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-600 to-purple-700">
      <div className="bg-white p-8 rounded-3xl shadow-2xl w-96">
        <h1 className="text-3xl font-bold text-center mb-6 bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
          🎙️ Asterisk Admin
        </h1>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Login
            </label>
            <input
              type="text"
              value={username}
              onChange={e => setUsername(e.target.value)}
              className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Mot de passe
            </label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500"
              required
            />
          </div>
          {error && <p className="text-red-600 text-sm">{error}</p>}
          <button
            type="submit"
            className="w-full px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-xl hover:shadow-lg font-semibold"
          >
            Se connecter
          </button>
        </form>
      </div>
    </div>
  );
};

// Dashboard Component
const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadDashboard();
    const interval = setInterval(loadDashboard, 30000);
    return () => clearInterval(interval);
  }, []);

  const loadDashboard = async () => {
    try {
      // Utiliser le endpoint dashboard complet au lieu de summary
      const data = await apiCall('/statistics/dashboard?tenant_id=1');
      setStats(data.data);
    } catch (error) {
      console.error('Erreur chargement dashboard:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="relative">
          <div className="animate-spin rounded-full h-16 w-16 border-4 border-blue-200"></div>
          <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-600 absolute top-0"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
            Tableau de Bord
          </h1>
          <p className="text-gray-500 mt-2">Vue d'ensemble de votre système</p>
        </div>
        <button
          onClick={loadDashboard}
          className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-xl hover:shadow-lg transform hover:scale-105 transition-all"
        >
          <RefreshCw className="w-5 h-5" />
          Actualiser
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard
          title="Appels Totaux"
          value={stats?.calls?.total_calls || 0}
          icon={<PhoneCall className="w-8 h-8" />}
          color="blue"
        />
        <StatCard
          title="Appels Actifs"
          value={stats?.calls?.active_calls_now || 0}
          icon={<Activity className="w-8 h-8" />}
          color="green"
        />
        <StatCard
          title="Taux de Réponse"
          value={`${stats?.calls?.answer_rate_percent || 0}%`}
          icon={<TrendingUp className="w-8 h-8" />}
          color="yellow"
        />
        <StatCard
          title="Endpoints Connectés"
          value={`${stats?.endpoints?.registered_endpoints || 0}/${
            stats?.endpoints?.total_endpoints || 0
          }`}
          icon={<Phone className="w-8 h-8" />}
          color="purple"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white rounded-2xl shadow-xl p-6 hover:shadow-2xl transition-all">
          <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-blue-100 rounded-lg">
              <Calendar className="w-6 h-6 text-blue-600" />
            </div>
            <h3 className="text-xl font-bold text-gray-900">Période Active</h3>
          </div>
          <div className="space-y-4">
            <div className="flex items-center justify-between p-4 bg-gradient-to-r from-blue-50 to-purple-50 rounded-xl">
              <span className="text-gray-600 font-medium">Début</span>
              <span className="font-bold text-gray-900">
                {stats?.period?.start || '-'}
              </span>
            </div>
            <div className="flex items-center justify-between p-4 bg-gradient-to-r from-purple-50 to-pink-50 rounded-xl">
              <span className="text-gray-600 font-medium">Fin</span>
              <span className="font-bold text-gray-900">
                {stats?.period?.end || '-'}
              </span>
            </div>
            <div className="flex items-center justify-between p-4 bg-gradient-to-r from-green-50 to-blue-50 rounded-xl">
              <span className="text-gray-600 font-medium">Files d'attente</span>
              <span className="font-bold text-gray-900">
                {stats?.queues?.total_queues || 0}
              </span>
            </div>
            <div className="flex items-center justify-between p-4 bg-gradient-to-r from-purple-50 to-pink-50 rounded-xl">
              <span className="text-gray-600 font-medium">Enregistrements</span>
              <span className="font-bold text-gray-900">
                {stats?.recordings?.total_recordings || 0}
              </span>
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-green-500 to-green-600 rounded-2xl shadow-xl p-6 text-white hover:shadow-2xl transition-all">
          <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-white bg-opacity-20 rounded-lg backdrop-blur">
              <Zap className="w-6 h-6" />
            </div>
            <h3 className="text-xl font-bold">Performance Globale</h3>
          </div>
          <div className="flex items-center justify-center h-40">
            <div className="text-center">
              <div className="text-7xl font-black mb-2 drop-shadow-lg">
                {stats?.calls?.answer_rate_percent || 0}%
              </div>
              <div className="text-lg font-medium opacity-90">
                Taux de Réponse
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Section Queues */}
      {stats?.queues?.queues && stats.queues.queues.length > 0 && (
        <div className="bg-white rounded-2xl shadow-xl p-6">
          <h3 className="text-xl font-bold text-gray-900 mb-4">
            Files d'Attente
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {stats.queues.queues.map((queue, index) => (
              <div
                key={index}
                className="p-4 bg-gradient-to-br from-blue-50 to-purple-50 rounded-xl border border-blue-200"
              >
                <div className="font-bold text-gray-900">
                  {queue.queue_name}
                </div>
                <div className="text-sm text-gray-600 mt-1">
                  Stratégie: {queue.strategy} • Timeout: {queue.timeout}s
                </div>
                <div className="text-sm text-gray-600">
                  Appels: {queue.total_calls || 0}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

// Tenants Management
const TenantsManager = () => {
  const [tenants, setTenants] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingTenant, setEditingTenant] = useState(null);
  const [formData, setFormData] = useState({ name: '' });

  useEffect(() => {
    loadTenants();
  }, []);

  const loadTenants = async () => {
    try {
      const data = await apiCall('/tenants');
      setTenants(data.data);
    } catch (error) {
      alert('Erreur chargement tenants');
    }
  };

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      if (editingTenant) {
        await apiCall(`/tenants/${editingTenant.id}`, 'PATCH', formData);
      } else {
        await apiCall('/tenants', 'POST', formData);
      }
      setShowModal(false);
      setFormData({ name: '' });
      setEditingTenant(null);
      loadTenants();
    } catch (error) {
      alert('Erreur lors de la sauvegarde: ' + error.message);
    }
  };

  const handleDelete = async id => {
    if (!window.confirm('Supprimer ce tenant ?')) return;
    try {
      await apiCall(`/tenants/${id}`, 'DELETE');
      loadTenants();
    } catch (error) {
      alert('Erreur lors de la suppression: ' + error.message);
    }
  };

  const openEditModal = tenant => {
    setEditingTenant(tenant);
    setFormData({ name: tenant.name });
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingTenant(null);
    setFormData({ name: '' });
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
            Gestion des Tenants
          </h1>
          <p className="text-gray-500 mt-2">
            Gérez vos clients et organisations
          </p>
        </div>
        <button
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-green-600 to-green-700 text-white rounded-xl hover:shadow-lg transform hover:scale-105 transition-all"
        >
          <Plus className="w-5 h-5" />
          Nouveau Tenant
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {tenants.map(tenant => (
          <div
            key={tenant.id}
            className="group relative overflow-hidden bg-white rounded-2xl shadow-xl hover:shadow-2xl transition-all transform hover:-translate-y-2"
          >
            <div className="absolute inset-0 bg-gradient-to-br from-blue-500 to-purple-600 opacity-0 group-hover:opacity-5 transition-opacity"></div>
            <div className="relative p-6">
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-3">
                  <div className="p-3 bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl shadow-lg">
                    <Users className="w-6 h-6 text-white" />
                  </div>
                  <div>
                    <h3 className="text-xl font-bold text-gray-900">
                      {tenant.name}
                    </h3>
                    <p className="text-sm text-gray-500 mt-1">
                      ID: {tenant.id}
                    </p>
                  </div>
                </div>
              </div>
              <div className="flex gap-2">
                <button
                  onClick={() => openEditModal(tenant)}
                  className="flex-1 px-4 py-3 bg-gray-100 text-gray-700 rounded-xl hover:bg-gray-200 flex items-center justify-center gap-2 font-medium transition-all"
                >
                  <Edit className="w-4 h-4" />
                  Modifier
                </button>
                <button
                  onClick={() => handleDelete(tenant.id)}
                  className="flex-1 px-4 py-3 bg-red-50 text-red-600 rounded-xl hover:bg-red-100 flex items-center justify-center gap-2 font-medium transition-all"
                >
                  <Trash2 className="w-4 h-4" />
                  Supprimer
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {showModal && (
        <Modal
          onClose={closeModal}
          title={editingTenant ? 'Modifier Tenant' : 'Nouveau Tenant'}
        >
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">
                Nom du Tenant
              </label>
              <input
                type="text"
                value={formData.name}
                onChange={e =>
                  setFormData({ ...formData, name: e.target.value })
                }
                className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all"
                required
                placeholder="Ex: Client A"
              />
            </div>
            <div className="flex gap-3 pt-4">
              <button
                type="submit"
                className="flex-1 px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-xl hover:shadow-lg font-semibold transition-all"
              >
                {editingTenant ? 'Mettre à jour' : 'Créer'}
              </button>
              <button
                type="button"
                onClick={closeModal}
                className="flex-1 px-6 py-3 bg-gray-200 text-gray-700 rounded-xl hover:bg-gray-300 font-semibold transition-all"
              >
                Annuler
              </button>
            </div>
          </form>
        </Modal>
      )}
    </div>
  );
};

// Endpoints Management
const EndpointsManager = () => {
  const [endpoints, setEndpoints] = useState([]);
  const [tenants, setTenants] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedTenant, setSelectedTenant] = useState('');
  const [formData, setFormData] = useState({
    tenant_id: '',
    password: '',
    transport: 'transport-udp',
  });

  // Filtres
  const [statusFilter, setStatusFilter] = useState('all'); // all, online, offline, in_call, available
  const [transportFilter, setTransportFilter] = useState('all'); // all, webrtc, udp
  const [searchQuery, setSearchQuery] = useState('');

  // Modal détails
  const [detailsModal, setDetailsModal] = useState(false);
  const [selectedEndpoint, setSelectedEndpoint] = useState(null);
  const [endpointDetails, setEndpointDetails] = useState(null);
  const [loadingDetails, setLoadingDetails] = useState(false);

  useEffect(() => {
    loadTenants();
    loadEndpoints();
  }, [selectedTenant]);

  const loadTenants = async () => {
    try {
      const data = await apiCall('/tenants');
      setTenants(data.data);
    } catch (error) {
      console.error('Erreur chargement tenants');
    }
  };

  const loadEndpoints = async () => {
    try {
      // Utiliser l'API enrichie pour avoir IP, Status, etc.
      const url = selectedTenant
        ? `/endpoints/enriched/all?tenant_id=${selectedTenant}`
        : '/endpoints/enriched/all';
      const data = await apiCall(url);
      // API V2 retourne une structure paginée: { data: { data: [...], total, page, limit } }
      setEndpoints(data.data?.data || data.data || []);
    } catch (error) {
      console.error('Erreur chargement endpoints');
    }
  };

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      await apiCall('/endpoints', 'POST', formData);
      setShowModal(false);
      setFormData({
        tenant_id: '',
        password: '',
        transport: 'transport-udp',
      });
      loadEndpoints();
      alert('Endpoint créé avec succès');
    } catch (error) {
      alert('Erreur: ' + error.message);
    }
  };

  const handleDelete = async id => {
    if (!window.confirm('Supprimer cet endpoint ?')) return;
    try {
      await apiCall(`/endpoints/${id}`, 'DELETE');
      loadEndpoints();
    } catch (error) {
      alert('Erreur lors de la suppression');
    }
  };

  const openDetailsModal = async endpoint => {
    setSelectedEndpoint(endpoint);
    setDetailsModal(true);
    setLoadingDetails(true);

    try {
      const data = await apiCall(`/endpoints/${endpoint.id}/details`);
      setEndpointDetails(data.data);
    } catch (error) {
      alert('Erreur lors du chargement des détails: ' + error.message);
    } finally {
      setLoadingDetails(false);
    }
  };

  const closeDetailsModal = () => {
    setDetailsModal(false);
    setSelectedEndpoint(null);
    setEndpointDetails(null);
  };

  const handleForceDisconnect = async endpointId => {
    if (
      !window.confirm(
        `Êtes-vous sûr de vouloir forcer la déconnexion de l'endpoint "${endpointId}" ?`
      )
    ) {
      return;
    }

    try {
      await apiCall(`/endpoints/${endpointId}/disconnect`, 'POST');
      alert(`Endpoint "${endpointId}" déconnecté avec succès`);

      // Recharger les endpoints et fermer le modal
      loadEndpoints();
      closeDetailsModal();
    } catch (error) {
      alert('Erreur lors de la déconnexion: ' + error.message);
    }
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
            Gestion des Endpoints
          </h1>
          <p className="text-gray-500 mt-2">
            Gérez vos extensions et dispositifs SIP
          </p>
        </div>
        <div className="flex gap-3">
          <select
            value={selectedTenant}
            onChange={e => setSelectedTenant(e.target.value)}
            className="px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all font-medium"
          >
            <option value="">Tous les tenants</option>
            {tenants.map(t => (
              <option key={t.id} value={t.id}>
                {t.name}
              </option>
            ))}
          </select>
          <button
            onClick={() => setShowModal(true)}
            className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-xl hover:shadow-lg transform hover:scale-105 transition-all"
          >
            <Plus className="w-5 h-5" />
            Nouvel Endpoint
          </button>
        </div>
      </div>

      {/* Statistiques */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-gradient-to-br from-green-50 to-green-100 rounded-xl p-6 border-2 border-green-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-green-600 text-sm font-semibold uppercase tracking-wide">
                Disponibles
              </p>
              <p className="text-3xl font-bold text-green-800 mt-2">
                {
                  endpoints.filter(
                    e =>
                      e.registered &&
                      e.active_channels === 0 &&
                      e.device_state === 'Not in use'
                  ).length
                }
              </p>
            </div>
            <div className="w-12 h-12 bg-green-500 rounded-full flex items-center justify-center">
              <div className="w-4 h-4 bg-white rounded-full"></div>
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-blue-50 to-blue-100 rounded-xl p-6 border-2 border-blue-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-blue-600 text-sm font-semibold uppercase tracking-wide">
                En appel
              </p>
              <p className="text-3xl font-bold text-blue-800 mt-2">
                {endpoints.filter(e => e.active_channels > 0).length}
              </p>
            </div>
            <div className="w-12 h-12 bg-blue-500 rounded-full flex items-center justify-center">
              <PhoneCall className="w-6 h-6 text-white" />
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-yellow-50 to-yellow-100 rounded-xl p-6 border-2 border-yellow-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-yellow-600 text-sm font-semibold uppercase tracking-wide">
                En ligne
              </p>
              <p className="text-3xl font-bold text-yellow-800 mt-2">
                {endpoints.filter(e => e.registered).length}
              </p>
            </div>
            <div className="w-12 h-12 bg-yellow-500 rounded-full flex items-center justify-center">
              <Activity className="w-6 h-6 text-white" />
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-red-50 to-red-100 rounded-xl p-6 border-2 border-red-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-red-600 text-sm font-semibold uppercase tracking-wide">
                Hors ligne
              </p>
              <p className="text-3xl font-bold text-red-800 mt-2">
                {endpoints.filter(e => !e.registered).length}
              </p>
            </div>
            <div className="w-12 h-12 bg-red-500 rounded-full flex items-center justify-center">
              <div className="w-4 h-4 bg-white rounded-full"></div>
