            <tbody className="divide-y divide-gray-100">
              {endpoints
                .filter(endpoint => {
                  // Filtre par statut
                  if (statusFilter !== 'all') {
                    if (
                      statusFilter === 'available' &&
                      !(
                        endpoint.registered &&
                        endpoint.active_channels === 0 &&
                        endpoint.device_state === 'Not in use'
                      )
                    ) {
                      return false;
                    }
                    if (
                      statusFilter === 'in_call' &&
                      !(endpoint.active_channels > 0)
                    ) {
                      return false;
                    }
                    if (statusFilter === 'online' && !endpoint.registered) {
                      return false;
                    }
                    if (statusFilter === 'offline' && endpoint.registered) {
                      return false;
                    }
                  }

                  // Filtre par transport
                  if (transportFilter !== 'all') {
                    const isWebRTC =
                      endpoint.transport &&
                      endpoint.transport.toLowerCase().includes('wss');
                    if (transportFilter === 'webrtc' && !isWebRTC) {
                      return false;
                    }
                    if (transportFilter === 'udp' && isWebRTC) {
                      return false;
                    }
