                      endpoint.id && endpoint.id.toLowerCase().includes(query);
                    const matchesIp =
                      endpoint.ip_address &&
                      endpoint.ip_address.toLowerCase().includes(query);
                    const matchesTenant =
                      endpoint.tenant_name &&
                      endpoint.tenant_name.toLowerCase().includes(query);

                    if (!matchesId && !matchesIp && !matchesTenant) {
                      return false;
