                      Direct Media
                    </p>
                    <p className="text-sm font-bold text-purple-900">
                      {endpointDetails.direct_media || 'N/A'}
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-purple-700 font-semibold">
                      DTMF Mode
                    </p>
                    <p className="text-sm font-bold text-purple-900">
                      {endpointDetails.dtmf_mode || 'N/A'}
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-purple-700 font-semibold">
                      RTP Symmetric
                    </p>
                    <p className="text-sm font-bold text-purple-900">
                      {endpointDetails.rtp_symmetric || 'N/A'}
                    </p>
                  </div>
                </div>
              </div>

              {/* Sécurité */}
              {endpointDetails.ami_details && (
                <div className="bg-gradient-to-br from-yellow-50 to-yellow-100 rounded-xl p-6 border-2 border-yellow-200">
                  <h3 className="text-lg font-bold text-yellow-900 mb-4 flex items-center gap-2">
                    <Power className="w-5 h-5" />
                    Sécurité & Avancé
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-sm text-yellow-700 font-semibold">
                        Type d'authentification
                      </p>
                      <p className="text-sm font-bold text-yellow-900">
                        {endpointDetails.auth_type || 'userpass'}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm text-yellow-700 font-semibold">
                        DTLS
                      </p>
                      <p className="text-sm font-bold text-yellow-900">
                        {endpointDetails.media_encryption || 'no'}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm text-yellow-700 font-semibold">
                        WebRTC
                      </p>
                      <p className="text-sm font-bold text-yellow-900">
                        {endpointDetails.webrtc || 'no'}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm text-yellow-700 font-semibold">
                        Force RPORT
                      </p>
                      <p className="text-sm font-bold text-yellow-900">
                        {endpointDetails.force_rport || 'yes'}
                      </p>
                    </div>
                  </div>
                </div>
              )}

              {/* Détails AMI Complets */}
              {endpointDetails.ami_details &&
                Object.keys(endpointDetails.ami_details).length > 0 && (
                  <div className="bg-gray-50 rounded-xl p-6 border-2 border-gray-200">
                    <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                      <Database className="w-5 h-5" />
                      Détails AMI Bruts
                    </h3>
                    <pre className="text-xs bg-white p-4 rounded-lg overflow-x-auto border border-gray-300 font-mono">
                      {JSON.stringify(endpointDetails.ami_details, null, 2)}
                    </pre>
                  </div>
                )}
            </div>
          ) : (
            <div className="py-12 text-center text-gray-500">
              Aucun détail disponible
            </div>
          )}
          <div className="mt-6 flex justify-between items-center gap-3">
            <div className="flex gap-3">
              {selectedEndpoint && selectedEndpoint.registered && (
                <button
                  onClick={() => handleForceDisconnect(selectedEndpoint.id)}
                  className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-red-500 to-red-600 text-white rounded-xl hover:shadow-lg transform hover:scale-105 transition-all font-semibold"
                  disabled={loadingDetails}
                >
                  <WifiOff className="w-5 h-5" />
                  Forcer déconnexion
                </button>
              )}
              <button
                onClick={() => {
                  // Navigation vers la page CDR filtrée par endpoint
                  // Pour l'instant, on affiche juste un message
                  alert(
                    `Historique CDR pour l'endpoint ${selectedEndpoint?.id} - À implémenter`
                  );
                }}
                className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-blue-500 to-blue-600 text-white rounded-xl hover:shadow-lg transform hover:scale-105 transition-all font-semibold"
                disabled={loadingDetails}
              >
                <FileText className="w-5 h-5" />
                Historique CDR
              </button>
            </div>
            <button
              onClick={closeDetailsModal}
              className="px-6 py-3 bg-gray-200 text-gray-700 rounded-xl hover:bg-gray-300 font-semibold transition-all"
            >
              Fermer
            </button>
          </div>
        </Modal>
      )}
    </div>
  );
};

// Queues Management
const QueuesManager = () => {
  const [queues, setQueues] = useState([]);
  const [selectedQueue, setSelectedQueue] = useState(null);
  const [members, setMembers] = useState([]);
  const [waitingCalls, setWaitingCalls] = useState([]);
  const [showAddMember, setShowAddMember] = useState(false);
  const [selectedAgents, setSelectedAgents] = useState([]);
  const [availableEndpoints, setAvailableEndpoints] = useState([]);
  const [showCreateQueue, setShowCreateQueue] = useState(false);
  const [showEditQueue, setShowEditQueue] = useState(false);
  const [selectedTenant, setSelectedTenant] = useState(1);
  const [tenants, setTenants] = useState([]);
  const [queueForm, setQueueForm] = useState({
    name: '',
    strategy: 'ringall',
    timeout: 20,
    retry: 5,
    wrapuptime: 15,
    maxlen: 0,
    tenant_id: 1,
  });

  useEffect(() => {
    loadTenants();
  }, []);

  useEffect(() => {
    if (selectedTenant) {
      loadQueues();
    }
  }, [selectedTenant]);

  useEffect(() => {
    if (selectedQueue) {
      loadMembers(selectedQueue);
    }
  }, [selectedQueue]);

  const loadTenants = async () => {
    try {
      const data = await apiCall('/tenants');
      setTenants(data.data || []);
    } catch (error) {
      console.error('Erreur chargement tenants');
    }
  };

  const loadQueues = async () => {
    try {
      // Utiliser l'endpoint enrichi pour avoir toutes les stats AMI en temps réel
      const data = await apiCall(
        `/queues/enriched?tenant_id=${selectedTenant}`
      );
      setQueues(data.data);
    } catch (error) {
      console.error('Erreur chargement queues');
    }
  };

  const loadAvailableEndpoints = async () => {
    try {
      const data = await apiCall(`/endpoints?tenant_id=${selectedTenant}`);
      // API V2 retourne une structure paginée: { data: { data: [...], total, page, limit } }
      setAvailableEndpoints(data.data?.data || data.data || []);
    } catch (error) {
      console.error('Erreur chargement endpoints');
      setAvailableEndpoints([]);
    }
  };

  const loadMembers = async queueName => {
    try {
      const data = await apiCall(`/queues/${queueName}/members/enriched`);
      setMembers(data.data);
    } catch (error) {
      console.error('Erreur chargement membres');
    }
  };

  const loadWaitingCalls = async queueName => {
    try {
      const data = await apiCall(`/queues/${queueName}/calls`);
      setWaitingCalls(data.data.calls || []);
    } catch (error) {
      console.error('Erreur chargement appels en attente');
      setWaitingCalls([]);
    }
  };

  const handlePause = async (queueName, memberInterface, paused) => {
    try {
      const action = paused ? 'unpause' : 'pause';
      await apiCall(
        `/queues/${queueName}/members/${encodeURIComponent(
          memberInterface
        )}/${action}`,
        'PATCH'
      );
      loadMembers(queueName);
    } catch (error) {
      alert('Erreur lors de la pause');
    }
  };

  const handleAddMember = async e => {
    e.preventDefault();
    try {
      // Ajouter chaque agent sélectionné
      for (const endpointId of selectedAgents) {
        const endpoint = availableEndpoints.find(ep => ep.id === endpointId);
        if (endpoint) {
          await apiCall(`/queues/${selectedQueue}/members`, 'POST', {
            tenantId: endpoint.tenantId || selectedTenant,
            endpointName: endpoint.id,
            penalty: 0,
          });
        }
      }
      setShowAddMember(false);
      setSelectedAgents([]);
      loadMembers(selectedQueue);
      alert(`${selectedAgents.length} agent(s) ajouté(s) avec succès !`);
    } catch (error) {
      alert('Erreur: ' + error.message);
    }
  };

  const handleRemoveMember = async memberInterface => {
    if (!window.confirm('Retirer cet agent ?')) return;
    try {
      await apiCall(
        `/queues/${selectedQueue}/members/${encodeURIComponent(
          memberInterface
        )}`,
        'DELETE'
      );
      loadMembers(selectedQueue);
    } catch (error) {
      alert('Erreur lors du retrait');
    }
  };

  const handleCreateQueue = async e => {
    e.preventDefault();
    try {
      const queueData = {
        ...queueForm,
        tenantId: selectedTenant,
      };
      await apiCall('/queues', 'POST', queueData);
      setShowCreateQueue(false);
      setQueueForm({
        name: '',
        strategy: 'ringall',
        timeout: 20,
        retry: 5,
        wrapuptime: 15,
        maxlen: 0,
        tenantId: selectedTenant,
      });
      loadQueues();
      alert('Queue créée avec succès !');
    } catch (error) {
      alert('Erreur: ' + error.message);
    }
  };

  const handleEditQueue = async e => {
    e.preventDefault();
    try {
      await apiCall(`/queues/${queueForm.name}`, 'PATCH', queueForm);
      setShowEditQueue(false);
      loadQueues();
      alert('Queue modifiée avec succès !');
    } catch (error) {
      alert('Erreur: ' + error.message);
    }
  };

  const handleDeleteQueue = async queueName => {
    if (!window.confirm(`Supprimer définitivement la queue "${queueName}" ?`))
      return;
    try {
      await apiCall(`/queues/${queueName}`, 'DELETE');
      if (selectedQueue === queueName) {
        setSelectedQueue(null);
      }
      loadQueues();
      alert('Queue supprimée avec succès !');
    } catch (error) {
      alert('Erreur: ' + error.message);
    }
  };

  const openEditQueue = queue => {
    setQueueForm({
      name: queue.name,
      strategy: queue.strategy,
      timeout: queue.timeout,
      retry: queue.retry,
      wrapuptime: queue.wrapuptime,
      maxlen: queue.maxlen,
      tenantId: queue.tenant_id,
    });
    setShowEditQueue(true);
  };

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
          Gestion des Files d'Attente
        </h1>
        <p className="text-gray-500 mt-2">Gérez vos queues et agents</p>
      </div>

      {/* Filtre par tenant */}
      <div className="bg-white rounded-2xl shadow-xl p-6">
        <div className="flex items-center gap-4">
          <label className="text-sm font-bold text-gray-700 whitespace-nowrap">
            Filtrer par tenant :
          </label>
          <select
            value={selectedTenant}
            onChange={e => {
              setSelectedTenant(parseInt(e.target.value));
              setSelectedQueue(null);
            }}
            className="flex-1 px-4 py-3 border-2 border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 transition-all font-semibold"
          >
            {tenants.map(tenant => (
              <option key={tenant.id} value={tenant.id}>
                {tenant.name} (ID: {tenant.id})
              </option>
            ))}
          </select>
          <div className="text-sm text-gray-500">{queues.length} queue(s)</div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 bg-white rounded-2xl shadow-xl p-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-gray-900">Files d'Attente</h2>
            <button
              onClick={() => setShowCreateQueue(true)}
              className="p-2 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-lg hover:shadow-lg transition-all"
              title="Créer une queue"
            >
              <Plus className="w-5 h-5" />
            </button>
          </div>
          <div className="space-y-3">
            {queues.map(queue => (
              <div
                key={queue.name}
                className={`relative group p-4 rounded-xl transition-all ${
                  selectedQueue === queue.name
                    ? 'bg-gradient-to-r from-blue-600 to-purple-600 text-white shadow-lg'
                    : 'bg-gray-50 hover:bg-gray-100 text-gray-900'
                }`}
              >
                <div
                  onClick={() => {
                    setSelectedQueue(queue.name);
                    loadMembers(queue.name);
                    loadWaitingCalls(queue.name);
                  }}
                  className="cursor-pointer"
                >
                  <div className="flex items-center gap-2">
                    <div className="font-bold text-lg">{queue.name}</div>
                    {queue.visual_state && queue.visual_state !== 'idle' && (
                      <span
                        className={`px-2 py-0.5 text-xs font-bold rounded-full ${
                          queue.visual_state === 'critical'
                            ? 'bg-red-500 text-white animate-pulse'
                            : queue.visual_state === 'busy'
                            ? 'bg-orange-500 text-white'
                            : queue.visual_state === 'active'
                            ? 'bg-green-500 text-white'
                            : ''
                        }`}
                      >
                        {queue.visual_state === 'critical'
                          ? '🔥 CRITIQUE'
                          : queue.visual_state === 'busy'
                          ? '⚠️ CHARGÉ'
                          : queue.visual_state === 'active'
                          ? '✓ ACTIF'
                          : ''}
                      </span>
                    )}
                  </div>
                  <div
                    className={`text-sm mt-1 ${
                      selectedQueue === queue.name
                        ? 'text-blue-100'
                        : 'text-gray-500'
                    }`}
                  >
                    {queue.strategy} •{' '}
                    {queue.members_total || queue.member_count || 0} agents
                    {queue.calls_waiting > 0 &&
                      ` • ${queue.calls_waiting} en attente`}
                  </div>
                </div>
                <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
                  <button
                    onClick={e => {
                      e.stopPropagation();
                      openEditQueue(queue);
                    }}
                    className="p-1.5 bg-white text-blue-600 rounded-lg hover:bg-blue-50 shadow-lg"
                    title="Modifier"
                  >
                    <Edit className="w-4 h-4" />
                  </button>
                  <button
                    onClick={e => {
                      e.stopPropagation();
                      handleDeleteQueue(queue.name);
                    }}
                    className="p-1.5 bg-white text-red-600 rounded-lg hover:bg-red-50 shadow-lg"
                    title="Supprimer"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="lg:col-span-2 bg-white rounded-2xl shadow-xl p-6">
          {selectedQueue ? (
            <>
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold text-gray-900">
                  Queue: {selectedQueue}
                </h2>
                <button
                  onClick={() => {
                    loadAvailableEndpoints();
                    setShowAddMember(true);
                  }}
                  className="px-5 py-3 bg-gradient-to-r from-green-600 to-green-700 text-white rounded-xl hover:shadow-lg flex items-center gap-2 font-semibold transform hover:scale-105 transition-all"
                >
                  <UserPlus className="w-5 h-5" />
                  Ajouter Agent
                </button>
              </div>

              {/* Statistiques en temps réel de la queue */}
              {(() => {
                const currentQueue = queues.find(q => q.name === selectedQueue);
                return (
                  currentQueue && (
                    <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-6">
                      <div className="bg-gradient-to-br from-blue-50 to-blue-100 p-4 rounded-xl border border-blue-200">
                        <p className="text-xs text-blue-600 font-semibold uppercase">
                          En attente
                        </p>
                        <p className="text-2xl font-bold text-blue-900">
                          {currentQueue.calls_waiting || 0}
                        </p>
                      </div>
                      <div className="bg-gradient-to-br from-green-50 to-green-100 p-4 rounded-xl border border-green-200">
                        <p className="text-xs text-green-600 font-semibold uppercase">
                          Disponibles
                        </p>
                        <p className="text-2xl font-bold text-green-900">
                          {currentQueue.members_available || 0}
                        </p>
                      </div>
                      <div className="bg-gradient-to-br from-yellow-50 to-yellow-100 p-4 rounded-xl border border-yellow-200">
                        <p className="text-xs text-yellow-600 font-semibold uppercase">
                          En appel
                        </p>
                        <p className="text-2xl font-bold text-yellow-900">
                          {currentQueue.members_in_call || 0}
                        </p>
                      </div>
                      <div className="bg-gradient-to-br from-purple-50 to-purple-100 p-4 rounded-xl border border-purple-200">
                        <p className="text-xs text-purple-600 font-semibold uppercase">
                          Complétés
                        </p>
                        <p className="text-2xl font-bold text-purple-900">
                          {currentQueue.calls_completed || 0}
                        </p>
                      </div>
                      <div className="bg-gradient-to-br from-red-50 to-red-100 p-4 rounded-xl border border-red-200">
                        <p className="text-xs text-red-600 font-semibold uppercase">
                          Abandonnés
                        </p>
                        <p className="text-2xl font-bold text-red-900">
                          {currentQueue.calls_abandoned || 0}
                        </p>
                      </div>
                    </div>
                  )
                );
              })()}

              {/* Appels en attente */}
              {waitingCalls.length > 0 && (
                <div className="mb-6">
                  <h3 className="text-lg font-bold text-gray-900 mb-3">
                    📞 Appels en attente ({waitingCalls.length})
                  </h3>
                  <div className="space-y-2">
                    {waitingCalls.map((call, index) => (
                      <div
                        key={index}
                        className="flex items-center justify-between p-4 bg-gradient-to-r from-orange-50 to-orange-100 rounded-xl border border-orange-200"
                      >
                        <div>
                          <div className="font-bold text-gray-900">
                            Position {call.position} -{' '}
                            {call.caller_id_name || call.caller_id_num}
                          </div>
                          <div className="text-sm text-gray-600">
                            {call.caller_id_num} • Attente:{' '}
                            {Math.floor(call.wait_time / 60)}m{' '}
                            {call.wait_time % 60}s
                          </div>
                        </div>
                        <div className="text-orange-600 font-bold">
                          ⏱️ {call.wait_time}s
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              <h3 className="text-lg font-bold text-gray-900 mb-4">
                Agents ({members.length})
              </h3>
              <div className="space-y-4">
                {members.map(member => (
                  <div
                    key={member.interface}
                    className="flex items-center justify-between p-5 bg-gradient-to-r from-gray-50 to-gray-100 rounded-xl hover:shadow-md transition-all"
                  >
                    <div className="flex items-center gap-4">
                      <div
                        className={`w-4 h-4 rounded-full shadow-lg ${
                          member.paused
                            ? 'bg-yellow-500'
                            : member.available ||
                              member.detailed_status === 'available'
                            ? 'bg-green-500'
                            : 'bg-red-500'
                        } animate-pulse`}
                        title={
                          member.paused
                            ? 'En pause'
                            : member.available ||
                              member.detailed_status === 'available'
                            ? 'Disponible'
                            : 'Déconnecté'
                        }
                      ></div>
                      <div>
                        <div className="font-bold text-gray-900">
                          {member.member_name || member.membername}
                        </div>
                        <div className="text-sm text-gray-600">
                          {member.interface} • Priorité: {member.penalty}
                          {(member.in_call ||
                            member.detailed_status === 'in_call') &&
                            ' • 📞 En appel'}
                          {member.calls_taken > 0 &&
                            ` • ${member.calls_taken} appels traités`}
                        </div>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button
                        onClick={() =>
                          handlePause(
                            selectedQueue,
                            member.interface,
                            member.paused
                          )
                        }
                        className={`px-5 py-3 rounded-xl flex items-center gap-2 font-semibold transition-all transform hover:scale-105 ${
                          member.paused
                            ? 'bg-green-100 text-green-700 hover:bg-green-200'
                            : 'bg-yellow-100 text-yellow-700 hover:bg-yellow-200'
                        }`}
                      >
                        {member.paused ? (
                          <Play className="w-4 h-4" />
                        ) : (
                          <Pause className="w-4 h-4" />
                        )}
                        {member.paused ? 'Reprendre' : 'Pause'}
                      </button>
                      <button
                        onClick={() => handleRemoveMember(member.interface)}
                        className="px-4 py-3 bg-red-50 text-red-600 rounded-xl hover:bg-red-100 font-semibold transition-all transform hover:scale-105"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </>
          ) : (
            <div className="text-center text-gray-400 py-16">
              <Headphones className="w-20 h-20 mx-auto mb-4 opacity-30" />
              <p className="text-xl font-medium">
                Sélectionnez une queue pour voir ses agents
              </p>
            </div>
          )}
        </div>
      </div>

      {showAddMember && (
        <Modal
          onClose={() => setShowAddMember(false)}
          title="Ajouter des Agents"
        >
          <form onSubmit={handleAddMember} className="space-y-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">
                Sélectionner les agents à ajouter (tenant {selectedTenant})
              </label>
              <div className="border-2 border-gray-200 rounded-xl p-4 max-h-64 overflow-y-auto space-y-2">
                {availableEndpoints.length === 0 ? (
                  <p className="text-gray-500 text-center py-4">
                    Aucun endpoint disponible pour ce tenant
                  </p>
                ) : (
                  availableEndpoints
                    .filter(
                      endpoint =>
                        !members.some(
                          m => m.interface === `PJSIP/${endpoint.id}`
                        )
                    )
                    .map(endpoint => (
                      <label
                        key={endpoint.id}
                        className="flex items-center gap-3 p-3 hover:bg-gray-50 rounded-lg cursor-pointer transition-all"
                      >
                        <input
                          type="checkbox"
                          value={endpoint.id}
                          checked={selectedAgents.includes(endpoint.id)}
                          onChange={e => {
                            if (e.target.checked) {
                              setSelectedAgents([
                                ...selectedAgents,
                                endpoint.id,
                              ]);
                            } else {
                              setSelectedAgents(
                                selectedAgents.filter(id => id !== endpoint.id)
                              );
                            }
                          }}
                          className="w-5 h-5 text-blue-600 rounded focus:ring-2 focus:ring-blue-500"
                        />
                        <div className="flex-1">
                          <div className="font-semibold text-gray-900">
                            {endpoint.id}
                          </div>
                          <div className="text-sm text-gray-500">
                            PJSIP/{endpoint.id}
                          </div>
                        </div>
                      </label>
                    ))
                )}
              </div>
              <p className="text-xs text-gray-500 mt-2">
                {selectedAgents.length} agent(s) sélectionné(s)
              </p>
            </div>
            <div className="flex gap-3 pt-4">
              <button
                type="submit"
                disabled={selectedAgents.length === 0}
                className="flex-1 px-6 py-3 bg-gradient-to-r from-green-600 to-green-700 text-white rounded-xl hover:shadow-lg font-semibold transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Ajouter ({selectedAgents.length})
              </button>
              <button
                type="button"
                onClick={() => {
                  setShowAddMember(false);
                  setSelectedAgents([]);
                }}
                className="flex-1 px-6 py-3 bg-gray-200 text-gray-700 rounded-xl hover:bg-gray-300 font-semibold transition-all"
              >
                Annuler
              </button>
            </div>
