// Active Calls Monitor
const ActiveCalls = () => {
  const [channels, setChannels] = useState([]);
  const [autoRefresh, setAutoRefresh] = useState(true);
  const [loading, setLoading] = useState(false);
  const [transferModal, setTransferModal] = useState(false);
  const [selectedChannel, setSelectedChannel] = useState(null);
  const [transferData, setTransferData] = useState({
    extension: '',
    context: 'client-a-context',
  });
  const [availableExtensions, setAvailableExtensions] = useState([]);

  useEffect(() => {
    loadChannels();
    let interval;
    if (autoRefresh) {
      interval = setInterval(loadChannels, 5000);
    }
    return () => clearInterval(interval);
  }, [autoRefresh]);

  const loadChannels = async () => {
    setLoading(true);
    try {
      const data = await apiCall('/api/asterisk/channels');
      setChannels(data.data?.events || []);
    } catch (error) {
      console.error('Erreur chargement canaux');
    } finally {
      setLoading(false);
    }
  };

  const hangupChannel = async channelName => {
    if (!window.confirm('Raccrocher cet appel ?')) return;
    try {
      await apiCall(
        `/api/asterisk/channels/${encodeURIComponent(channelName)}`,
        'DELETE'
      );
      loadChannels();
    } catch (error) {
      alert('Erreur lors du raccrochage');
    }
  };

  const openTransferModal = async (channelName, context) => {
    setSelectedChannel(channelName);
    const ctx = context || 'client-a-context';
    setTransferData({
      extension: '',
      context: ctx,
    });

    // Charger les extensions disponibles pour ce contexte
    try {
      const data = await apiCall(
        `/api/asterisk/extensions/available?context=${ctx}`
      );
      setAvailableExtensions(data.data || []);
    } catch (error) {
      console.error('Erreur chargement extensions disponibles');
      setAvailableExtensions([]);
    }

    setTransferModal(true);
  };

  const closeTransferModal = () => {
    setTransferModal(false);
    setSelectedChannel(null);
    setTransferData({ extension: '', context: 'client-a-context' });
  };

  const handleBlindTransfer = async () => {
    if (!transferData.extension.trim()) {
      alert('Veuillez saisir une extension de destination');
      return;
    }

    try {
      await apiCall('/api/asterisk/transfer/blind', 'POST', {
        channelName: selectedChannel,
        extension: transferData.extension,
        context: transferData.context,
      });
      alert(`Transfert vers ${transferData.extension} effectue avec succes`);
      closeTransferModal();
      loadChannels();
    } catch (error) {
      alert(
        'Erreur lors du transfert: ' + (error.message || 'Erreur inconnue')
      );
    }
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
            Appels Actifs
          </h1>
          <p className="text-gray-500 mt-2">
            Surveillez les appels en temps réel
          </p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => setAutoRefresh(!autoRefresh)}
            className={`px-6 py-3 rounded-xl flex items-center gap-2 font-semibold transition-all transform hover:scale-105 ${
              autoRefresh
                ? 'bg-gradient-to-r from-green-600 to-green-700 text-white shadow-lg'
                : 'bg-gray-200 text-gray-700'
            }`}
          >
            <Activity className="w-5 h-5" />
            {autoRefresh ? 'Auto-refresh ON' : 'Auto-refresh OFF'}
          </button>
          <button
            onClick={loadChannels}
            disabled={loading}
            className="px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-xl hover:shadow-lg flex items-center gap-2 font-semibold disabled:bg-gray-400 transition-all"
          >
            <RefreshCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
            Actualiser
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
        {channels.length === 0 ? (
          <div className="text-center py-16 text-gray-400">
            <PhoneCall className="w-20 h-20 mx-auto mb-4 opacity-30" />
            <p className="text-xl font-medium">Aucun appel actif</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gradient-to-r from-gray-50 to-gray-100">
                <tr>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-600 uppercase tracking-wider">
                    Canal
                  </th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-600 uppercase tracking-wider">
                    État
                  </th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-600 uppercase tracking-wider">
                    Contexte
                  </th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-600 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {channels.map((channel, idx) => (
                  <tr key={idx} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 text-sm font-bold text-gray-900">
                      {channel.channel || 'N/A'}
                    </td>
                    <td className="px-6 py-4">
                      <span className="px-3 py-1 rounded-lg text-xs font-bold bg-gradient-to-r from-green-100 to-green-200 text-green-800">
                        Actif
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      {channel.context || '-'}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex gap-2">
                        <button
                          onClick={() =>
                            openTransferModal(channel.channel, channel.context)
                          }
                          className="px-4 py-2 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-xl hover:shadow-lg text-sm font-semibold transition-all"
                        >
                          Transferer
                        </button>
                        <button
                          onClick={() => hangupChannel(channel.channel)}
                          className="px-4 py-2 bg-gradient-to-r from-red-600 to-red-700 text-white rounded-xl hover:shadow-lg text-sm font-semibold transition-all"
                        >
                          Raccrocher
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Modal de transfert d'appel */}
      {transferModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-md w-full mx-4">
            <h2 className="text-2xl font-bold text-gray-800 mb-6">
              Transferer l'appel
            </h2>

            <div className="space-y-4 mb-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Canal source
                </label>
                <input
                  type="text"
                  value={selectedChannel || ''}
                  disabled
                  className="w-full px-4 py-3 border border-gray-300 rounded-xl bg-gray-50 text-gray-600 text-sm"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Extension de destination *
                </label>
                {availableExtensions.length > 0 ? (
                  <select
                    value={transferData.extension}
                    onChange={e =>
                      setTransferData({
                        ...transferData,
                        extension: e.target.value,
                      })
                    }
                    className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                    autoFocus
                  >
                    <option value="">-- Sélectionner une extension --</option>
                    {availableExtensions.map(ext => (
                      <option key={ext} value={ext}>
                        {ext}
                      </option>
                    ))}
                  </select>
                ) : (
                  <div className="w-full px-4 py-3 border border-gray-300 rounded-xl bg-gray-50 text-gray-500 text-sm">
                    Aucune extension disponible
                  </div>
                )}
              </div>
            </div>

            <div className="flex gap-3">
              <button
                onClick={handleBlindTransfer}
                className="flex-1 px-6 py-3 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-xl hover:shadow-lg font-semibold transition-all"
              >
                Transferer
              </button>
              <button
                onClick={closeTransferModal}
                className="flex-1 px-6 py-3 bg-gray-200 text-gray-700 rounded-xl hover:bg-gray-300 font-semibold transition-all"
              >
                Annuler
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// Statistics Component
